function e(e){if(!e)return``;let t=new Date,n=new Date(e),r=t.getTime()-n.getTime();if(r<6e4)return`刚刚`;if(r<36e5)return Math.floor(r/6e4)+`分钟前`;if(r<864e5)return Math.floor(r/36e5)+`小时前`;if(r<6048e5)return Math.floor(r/864e5)+`天前`;let i=n.getFullYear(),a=String(n.getMonth()+1).padStart(2,`0`),o=String(n.getDate()).padStart(2,`0`);return i===t.getFullYear()?`${a}-${o}`:`${i}-${a}-${o}`}function t(e){if(!e)return``;let t=new Date(e);return`${t.getFullYear()}-${String(t.getMonth()+1).padStart(2,`0`)}-${String(t.getDate()).padStart(2,`0`)} ${String(t.getHours()).padStart(2,`0`)}:${String(t.getMinutes()).padStart(2,`0`)}`}function n(e){if(!e)return``;let t=new Date(e);return`${t.getFullYear()}-${String(t.getMonth()+1).padStart(2,`0`)}-${String(t.getDate()).padStart(2,`0`)}`}export{t as n,e as r,n as t};